// ===== PluginDescriptor.java =====
package com.pluginframework.core;

import java.io.*;
import java.util.*;

/**
 * 插件描述符 - 包含插件的所有元数据信息
 */
public class PluginDescriptor implements Serializable {
    private static final long serialVersionUID = 1L;

    private String id;                    // 插件唯一标识
    private String name;                 // 插件名称
    private String version;              // 版本号 (语义化版本)
    private String mainClass;            // 主类全限定名
    private String description;          // 插件描述
    private List<Dependency> dependencies = new ArrayList<>();  // 依赖列表
    private List<String> exportedPackages = new ArrayList<>();  // 导出包
    private List<String> importedPackages = new ArrayList<>();  // 导入包
    private Map<String, Object> metadata = new HashMap<>();     // 自定义元数据

    // 生命周期钩子
    private String onLoad;               // 加载时执行
    private String onStart;              // 启动时执行
    private String onStop;               // 停止时执行

    public PluginDescriptor() {}

    // Getters and Setters
    public String getId() { return id; }
    public void setId(String id) { this.id = id; }

    public String getName() { return name; }
    public void setName(String name) { this.name = name; }

    public String getVersion() { return version; }
    public void setVersion(String version) { this.version = version; }

    public String getMainClass() { return mainClass; }
    public void setMainClass(String mainClass) { this.mainClass = mainClass; }

    public String getDescription() { return description; }
    public void setDescription(String description) { this.description = description; }

    public List<Dependency> getDependencies() { return dependencies; }
    public void setDependencies(List<Dependency> dependencies) { this.dependencies = dependencies; }

    public List<String> getExportedPackages() { return exportedPackages; }
    public void setExportedPackages(List<String> exportedPackages) { this.exportedPackages = exportedPackages; }

    public List<String> getImportedPackages() { return importedPackages; }
    public void setImportedPackages(List<String> importedPackages) { this.importedPackages = importedPackages; }

    public Map<String, Object> getMetadata() { return metadata; }
    public void setMetadata(Map<String, Object> metadata) { this.metadata = metadata; }

    public String getOnLoad() { return onLoad; }
    public void setOnLoad(String onLoad) { this.onLoad = onLoad; }

    public String getOnStart() { return onStart; }
    public void setOnStart(String onStart) { this.onStart = onStart; }

    public String getOnStop() { return onStop; }
    public void setOnStop(String onStop) { this.onStop = onStop; }

    @Override
    public String toString() {
        return "PluginDescriptor{" +
                "id='" + id + '\'' +
                ", name='" + name + '\'' +
                ", version='" + version + '\'' +
                ", mainClass='" + mainClass + '\'' +
                '}';
    }

    /**
     * 依赖描述
     */
    public static class Dependency implements Serializable {
        private static final long serialVersionUID = 1L;

        private String pluginId;          // 依赖的插件ID
        private String versionRange;      // 版本范围 (e.g., "1.0.0", "[1.0.0,2.0.0)")

        public Dependency() {}

        public Dependency(String pluginId, String versionRange) {
            this.pluginId = pluginId;
            this.versionRange = versionRange;
        }

        public String getPluginId() { return pluginId; }
        public void setPluginId(String pluginId) { this.pluginId = pluginId; }

        public String getVersionRange() { return versionRange; }
        public void setVersionRange(String versionRange) { this.versionRange = versionRange; }

        @Override
        public String toString() {
            return "Dependency{" +
                    "pluginId='" + pluginId + '\'' +
                    ", versionRange='" + versionRange + '\'' +
                    '}';
        }
    }
}
