// ===== SemanticVersion.java =====
package com.pluginframework.core.util;

import java.util.regex.*;

/**
 * 语义化版本 (Semantic Versioning) 解析与比较
 * 格式: MAJOR.MINOR.PATCH[-PRERELEASE][+BUILD]
 * 示例: 1.2.3-alpha.1+build.123
 */
public class SemanticVersion implements Comparable<SemanticVersion> {

    private static final Pattern VERSION_PATTERN = 
        Pattern.compile("^(\\d+)\\.(\\d+)\\.(\\d+)(?:-([a-zA-Z0-9.]+))?(?:\\+([a-zA-Z0-9.]+))?$");

    private final int major;
    private final int minor;
    private final int patch;
    private final String preRelease;
    private final String build;

    public SemanticVersion(String version) {
        Matcher matcher = VERSION_PATTERN.matcher(version);
        if (!matcher.matches()) {
            throw new IllegalArgumentException("Invalid version format: " + version);
        }
        this.major = Integer.parseInt(matcher.group(1));
        this.minor = Integer.parseInt(matcher.group(2));
        this.patch = Integer.parseInt(matcher.group(3));
        this.preRelease = matcher.group(4);
        this.build = matcher.group(5);
    }

    public SemanticVersion(int major, int minor, int patch) {
        this(major, minor, patch, null, null);
    }

    public SemanticVersion(int major, int minor, int patch, String preRelease, String build) {
        this.major = major;
        this.minor = minor;
        this.patch = patch;
        this.preRelease = preRelease;
        this.build = build;
    }

    /**
     * 检查当前版本是否满足版本范围
     * 版本范围格式:
     *   "1.0.0"        - 精确匹配
     *   "^1.0.0"       - 兼容更新 (>=1.0.0, <2.0.0)
     *   "~1.0.0"       - 补丁更新 (>=1.0.0, <1.1.0)
     *   ">=1.0.0"      - 大于等于
     *   "[1.0.0,2.0.0)" - 区间 (左闭右开)
     */
    public boolean satisfies(String range) {
        if (range.startsWith("^")) {
            // 兼容更新
            SemanticVersion base = new SemanticVersion(range.substring(1));
            return this.compareTo(base) >= 0 && 
                   this.compareTo(new SemanticVersion(base.major + 1, 0, 0)) < 0;
        } else if (range.startsWith("~")) {
            // 补丁更新
            SemanticVersion base = new SemanticVersion(range.substring(1));
            return this.compareTo(base) >= 0 &&
                   this.compareTo(new SemanticVersion(base.major, base.minor + 1, 0)) < 0;
        } else if (range.startsWith(">=")) {
            return this.compareTo(new SemanticVersion(range.substring(2))) >= 0;
        } else if (range.startsWith(">")) {
            return this.compareTo(new SemanticVersion(range.substring(1))) > 0;
        } else if (range.startsWith("<=")) {
            return this.compareTo(new SemanticVersion(range.substring(2))) <= 0;
        } else if (range.startsWith("<")) {
            return this.compareTo(new SemanticVersion(range.substring(1))) < 0;
        } else if (range.startsWith("[")) {
            // 区间解析 [min,max) 或 [min,max]
            return parseRange(range);
        } else {
            // 精确匹配
            return this.compareTo(new SemanticVersion(range)) == 0;
        }
    }

    private boolean parseRange(String range) {
        // 移除方括号
        String inner = range.substring(1, range.length() - 1);
        String[] parts = inner.split(",");
        if (parts.length != 2) {
            throw new IllegalArgumentException("Invalid range format: " + range);
        }

        String min = parts[0].trim();
        String max = parts[1].trim();
        boolean minInclusive = range.startsWith("[");
        boolean maxInclusive = range.endsWith("]");

        boolean minOk = min.isEmpty() || 
            (minInclusive ? this.compareTo(new SemanticVersion(min)) >= 0 : this.compareTo(new SemanticVersion(min)) > 0);

        boolean maxOk = max.isEmpty() ||
            (maxInclusive ? this.compareTo(new SemanticVersion(max)) <= 0 : this.compareTo(new SemanticVersion(max)) < 0);

        return minOk && maxOk;
    }

    @Override
    public int compareTo(SemanticVersion other) {
        int cmp = Integer.compare(this.major, other.major);
        if (cmp != 0) return cmp;

        cmp = Integer.compare(this.minor, other.minor);
        if (cmp != 0) return cmp;

        cmp = Integer.compare(this.patch, other.patch);
        if (cmp != 0) return cmp;

        // 无预发布版本 > 有预发布版本
        if (this.preRelease == null && other.preRelease == null) return 0;
        if (this.preRelease == null) return 1;
        if (other.preRelease == null) return -1;

        return comparePreRelease(this.preRelease, other.preRelease);
    }

